import { type Type } from "arktype"
import { jsonSchemaToType } from "@ark/json-schema"

/**
 * Implement the bidirectional ArkType <-> JSON Schema round trip.
 *
 * `roundTrip(schema)` MUST:
 *   1. Export `schema` to JSON Schema (draft-2020-12) via `schema.toJsonSchema()`.
 *   2. Re-parse the resulting JSON Schema back into an ArkType `Type` using
 *      `@ark/json-schema`.
 *   3. Return the re-parsed Type.
 */
export function roundTrip(schema: Type): Type {
  const jsonSchema = exportJsonSchema(schema)
  return jsonSchemaToType(jsonSchema) as unknown as Type
}

/**
 * Implement the JSON Schema export used as the round-trip intermediate.
 * The returned object MUST contain `$schema` set to the draft-2020-12 URI:
 *   https://json-schema.org/draft/2020-12/schema
 */
export function exportJsonSchema(schema: Type): object {
  const jsonSchema = schema.toJsonSchema()
  if (!jsonSchema || typeof jsonSchema !== "object") {
    throw new Error("toJsonSchema did not return a valid object")
  }
  return {
    $schema: "https://json-schema.org/draft/2020-12/schema",
    ...jsonSchema,
  }
}

import * as fs from "fs"
import { type } from "arktype"
import { exportJsonSchema, roundTrip } from "./roundTrip.js"

function main() {
  try {
    const inputRaw = fs.readFileSync(0, "utf-8")
    if (!inputRaw.trim()) {
      console.error("Input is empty")
      process.exit(1)
    }
    const input = JSON.parse(inputRaw)

    const { schema: schemaDef, corpus } = input
    if (schemaDef === undefined || !Array.isArray(corpus)) {
      console.error("Invalid input format. Must be { schema: ..., corpus: [...] }")
      process.exit(1)
    }

    const originalType = type(schemaDef)
    const jsonSchema = exportJsonSchema(originalType)
    const roundTrippedType = roundTrip(originalType)

    const agreements = corpus.map((payload: any, index: number) => {
      const originalAccept = originalType.allows(payload)
      const roundTrippedAccept = roundTrippedType.allows(payload)
      const agree = originalAccept === roundTrippedAccept
      return {
        index,
        originalAccept,
        roundTrippedAccept,
        agree,
      }
    })

    const allAgree = agreements.every((a) => a.agree)

    const output = {
      jsonSchema,
      agreements,
      allAgree,
    }

    console.log(JSON.stringify(output, null, 2))
    process.exit(allAgree ? 0 : 1)
  } catch (err: any) {
    console.error("Error running check:", err)
    process.exit(1)
  }
}

main()

